sys_script.script:
(function executeRule(current, previous) {
  var returnRequestSysId = current.getValue('return_request');
  if (!returnRequestSysId) {
    gs.warn('CircleBack: Device Record inserted without a linked Return Request');
    return;
  }
  var gr = new GlideRecord('x_1845356_circle_0_return_request');
  if (gr.get(returnRequestSysId)) {
    gr.setValue('status', 'device_received');
    gr.update();
    gs.info('CircleBack: Return Request ' + gr.getValue('return_reference') + ' status updated to Device Received');
  }
})(current, previous);
